def is_actionable(body):
    if body.get("type") != "message":
        return False
    frm = body.get("from") or {}
    if frm.get("id", "") == BOT_FROM_ID:
        return False
    # Rosi only.
    if frm.get("aadObjectId", "") != ROSI_AAD_ID:
        return False
    text = body.get("text", "") or ""
    if not text.strip():
        return False
    # 1:1 personal chat — respond to everything Rosi says.
    conv = body.get("conversation", {}) or {}
    if conv.get("conversationType", "") == "personal":
        return True
    # Group chat / Teams channel — only fire when this bot is @-mentioned.
    # Most reliable: walk the entities array and look for a mention whose
    # 'mentioned.id' matches our BOT_FROM_ID. Falls back to text keyword
    # match for clients that don't populate entities cleanly.
    for e in (body.get("entities") or []):
        if e.get("type") == "mention":
            m = e.get("mentioned") or {}
            if m.get("id", "") == BOT_FROM_ID:
                return True
    tl = text.lower()
    if "<at" in tl and ("rosi's assistant" in tl or "rosi\u2019s assistant" in tl or "rosi cabrera claude" in tl):
        return True
    return False



